// src/pages/Home.jsx
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import './Home.css';

const POPULAR_ROUTES = [
  { from: 'Delhi', to: 'Mumbai' },
  { from: 'Bangalore', to: 'Chennai' },
  { from: 'Hyderabad', to: 'Kolkata' },
  { from: 'Pune', to: 'Ahmedabad' },
];

function Home() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ from: '', to: '', date: '', type: 'ALL' });
  const [errors, setErrors] = useState({});

  const today = new Date().toISOString().split('T')[0];

  const validate = () => {
    const e = {};
    if (!form.from.trim()) e.from = 'From location is required';
    if (!form.to.trim())   e.to   = 'To location is required';
    if (!form.date)        e.date = 'Travel date is required';
    if (form.from.trim().toLowerCase() === form.to.trim().toLowerCase())
      e.to = 'Source and destination cannot be same';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (!validate()) return;
    const params = new URLSearchParams(form).toString();
    navigate(`/search?${params}`);
  };

  const fillRoute = (route) => {
    setForm((f) => ({ ...f, from: route.from, to: route.to }));
    setErrors({});
  };

  return (
    <div className="home-page">
      {/* Hero Section */}
      <section className="hero-section">
        <div className="hero-bg-circles">
          <div className="circle c1"></div>
          <div className="circle c2"></div>
          <div className="circle c3"></div>
        </div>
        <div className="container hero-content">
          <div className="hero-badge">🇮🇳 India's Smart Travel Aggregator</div>
          <h1 className="hero-title">
            Compare <span className="highlight">Bus, Train</span> &<br />
            <span className="highlight">Flight</span> in One Place
          </h1>
          <p className="hero-subtitle">
            Search all travel modes simultaneously. Compare prices, timings, and
            duration — then book directly on the platform of your choice.
          </p>

          {/* Search Card */}
          <div className="search-card">
            <form className="search-form" onSubmit={handleSearch}>
              <div className="search-grid">
                <div className="form-group">
                  <label>From</label>
                  <input
                    type="text"
                    placeholder="e.g. Delhi"
                    value={form.from}
                    onChange={(e) => setForm({ ...form, from: e.target.value })}
                  />
                  {errors.from && <span className="error-msg">{errors.from}</span>}
                </div>

                <div className="swap-btn-wrap">
                  <button type="button" className="swap-btn"
                    onClick={() => setForm({ ...form, from: form.to, to: form.from })}>
                    ⇄
                  </button>
                </div>

                <div className="form-group">
                  <label>To</label>
                  <input
                    type="text"
                    placeholder="e.g. Mumbai"
                    value={form.to}
                    onChange={(e) => setForm({ ...form, to: e.target.value })}
                  />
                  {errors.to && <span className="error-msg">{errors.to}</span>}
                </div>

                <div className="form-group">
                  <label>Travel Date</label>
                  <input
                    type="date"
                    min={today}
                    value={form.date}
                    onChange={(e) => setForm({ ...form, date: e.target.value })}
                  />
                  {errors.date && <span className="error-msg">{errors.date}</span>}
                </div>

                <div className="form-group">
                  <label>Mode</label>
                  <select value={form.type} onChange={(e) => setForm({ ...form, type: e.target.value })}>
                    <option value="ALL">All Modes</option>
                    <option value="BUS">Bus Only</option>
                    <option value="TRAIN">Train Only</option>
                    <option value="FLIGHT">Flight Only</option>
                  </select>
                </div>

                <button type="submit" className="search-submit-btn">
                  🔍 Search Travel
                </button>
              </div>
            </form>

            {/* Popular Routes */}
            <div className="popular-routes">
              <span className="popular-label">Popular:</span>
              {POPULAR_ROUTES.map((r, i) => (
                <button key={i} className="route-chip" onClick={() => fillRoute(r)}>
                  {r.from} → {r.to}
                </button>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* Features */}
      <section className="features-section container">
        <h2 className="section-title">Why Choose GoBuddy?</h2>
        <div className="features-grid">
          {[
            { icon: '🚌', title: 'Bus', desc: 'Compare 1000+ bus operators with real-time seat availability via RedBus API.' },
            { icon: '🚆', title: 'Train', desc: 'Check IRCTC schedules, PNR status, fare charts for all train classes.' },
            { icon: '✈️', title: 'Flight', desc: 'Lowest airfares from Skyscanner API across all airlines and routes.' },
            { icon: '⚡', title: 'Instant Compare', desc: 'Side-by-side comparison of price, time, and duration in one view.' },
            { icon: '🔒', title: 'Secure Login', desc: 'JWT-secured accounts with personal search history and profiles.' },
            { icon: '📱', title: 'Fully Responsive', desc: 'Seamless experience across desktop, tablet, and mobile devices.' },
          ].map((f, i) => (
            <div key={i} className="feature-card">
              <div className="feature-icon">{f.icon}</div>
              <h3>{f.title}</h3>
              <p>{f.desc}</p>
            </div>
          ))}
        </div>
      </section>

      {/* Stats */}
      <section className="stats-section">
        <div className="container stats-grid">
          {[
            { value: '50+', label: 'Cities Covered' },
            { value: '3',   label: 'Travel Modes' },
            { value: '40%', label: 'Planning Time Saved' },
            { value: '24/7', label: 'Available' },
          ].map((s, i) => (
            <div key={i} className="stat-item">
              <div className="stat-value">{s.value}</div>
              <div className="stat-label">{s.label}</div>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}

export default Home;
